package genxsolution.vms.vmsbackend.vehicle_management.vehicle_type.service;
import genxsolution.vms.vmsbackend.vehicle_management.exception.VehicleResourceNotFoundException; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_type.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_type.mapper.VehicleTypeMapper; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_type.repository.VehicleTypeRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleTypeService { private final VehicleTypeRepository repository; private final VehicleTypeMapper mapper; public VehicleTypeService(VehicleTypeRepository repository,VehicleTypeMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleTypeResponse> list(){ return repository.findAll().stream().map(mapper::toResponse).toList(); } public VehicleTypeResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleType", id.toString())); } public VehicleTypeResponse create(VehicleTypeUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleTypeResponse update(UUID id,VehicleTypeUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleType", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new VehicleResourceNotFoundException("VehicleType", id.toString()); } }
